class Solution:
    def orderlyQueue(self, s, k):
        if k > 1:
            return ''.join(sorted(s))
        best = s
        cur = s
        for _ in range(len(s)):
            cur = cur[1:] + cur[0]
            if cur < best:
                best = cur
        return best

